(window.webpackJsonp=window.webpackJsonp||[]).push([[98],{604:function(t,e,n){"use strict";n.r(e);var a=n(29),o=Object(a.a)({},(function(){var t=this,e=t.$createElement,n=t._self._c||e;return n("ContentSlotsDistributor",{attrs:{"slot-key":t.$parent.slotKey}},[n("p",[t._v("HTTP（HyperTextTransferProtocol）即超文本传输协议，目前网页传输的的通用协议。HTTP协议采用了请求/响应模型，浏览器或其他客户端发出请求，服务器给与响应。就整个网络资源传输而言，包括message-header和message-body两部分。首先传递message- header，即http header消息 。")]),t._v(" "),n("p",[t._v("1）header分为三部分：第一部分为HTTP协议的版本(HTTP-Version)；\n第二部分为状态代码(Status)；\n第三部分为原因短语(Reason-Phrase)。")]),t._v(" "),n("p",[t._v("3）http header 消息通常被分为4个部分：general  header, request header, response header, entity header。但是这种分法就理解而言，感觉界限不太明确。根据维基百科对http header内容的组织形式，大体分为Request和Response两部分。")]),t._v(" "),n("p",[t._v("Requests部分\nHeader\t解释\t示例\nAccept\t指定客户端能够接收的内容类型\tAccept: text/plain, text/html\nAccept-Charset\t浏览器可以接受的字符编码集。\tAccept-Charset: iso-8859-5\nAccept-Encoding\t指定浏览器可以支持的web服务器返回内容压缩编码类型。\tAccept-Encoding: compress, gzip\nAccept-Language\t浏览器可接受的语言\tAccept-Language: en,zh\nAccept-Ranges\t可以请求网页实体的一个或者多个子范围字段\tAccept-Ranges: bytes\nAuthorization\tHTTP授权的授权证书\tAuthorization: Basic QWxhZGRpbjpvcGVuIHNlc2FtZQ==\nCache-Control\t指定请求和响应遵循的缓存机制\tCache-Control: no-cache\nConnection\t表示是否需要持久连接。（HTTP 1.1默认进行持久连接）\tConnection: close\nCookie\tHTTP请求发送时，会把保存在该请求域名下的所有cookie值一起发送给web服务器。\tCookie: $Version=1; Skin=new;\nContent-Length\t请求的内容长度\tContent-Length: 348\nContent-Type\t请求的与实体对应的MIME信息\tContent-Type: application/x-www-form-urlencoded\nDate\t请求发送的日期和时间\tDate: Tue, 15 Nov 2010 08:12:31 GMT\nExpect\t请求的特定的服务器行为\tExpect: 100-continue\nFrom\t发出请求的用户的Email\tFrom: user@email.com\nHost\t指定请求的服务器的域名和端口号\tHost: www.zcmhi.com\nIf-Match\t只有请求内容与实体相匹配才有效\tIf-Match: “737060cd8c284d8af7ad3082f209582d”\nIf-Modified-Since\t如果请求的部分在指定时间之后被修改则请求成功，未被修改则返回304代码\tIf-Modified-Since: Sat, 29 Oct 2010 19:43:31 GMT\nIf-None-Match\t如果内容未改变返回304代码，参数为服务器先前发送的Etag，与服务器回应的Etag比较判断是否改变\tIf-None-Match: “737060cd8c284d8af7ad3082f209582d”\nIf-Range\t如果实体未改变，服务器发送客户端丢失的部分，否则发送整个实体。参数也为Etag\tIf-Range: “737060cd8c284d8af7ad3082f209582d”\nIf-Unmodified-Since\t只在实体在指定时间之后未被修改才请求成功\tIf-Unmodified-Since: Sat, 29 Oct 2010 19:43:31 GMT\nMax-Forwards\t限制信息通过代理和网关传送的时间\tMax-Forwards: 10\nPragma\t用来包含实现特定的指令\tPragma: no-cache\nProxy-Authorization\t连接到代理的授权证书\tProxy-Authorization: Basic QWxhZGRpbjpvcGVuIHNlc2FtZQ==\nRange\t只请求实体的一部分，指定范围\tRange: bytes=500-999\nReferer\t先前网页的地址，当前请求网页紧随其后,即来路，来源，来自\tReferer: http://www.zcmhi.com/archives/71.html\nTE\t客户端愿意接受的传输编码，并通知服务器接受接受尾加头信息\tTE: trailers,deflate;q=0.5\nUpgrade\t向服务器指定某种传输协议以便服务器进行转换（如果支持）\tUpgrade: HTTP/2.0, SHTTP/1.3, IRC/6.9, RTA/x11\nUser-Agent\tUser-Agent的内容包含发出请求的用户信息，浏览器类型，客户端\tUser-Agent: Mozilla/5.0 (Linux; X11) Mozilla/5.0 (Windows NT 10.0; WOW64) Chrome/78.0.3904.108\nVia\t通知中间网关或代理服务器地址，通信协议\tVia: 1.0 fred, 1.1 nowhere.com (Apache/1.1)\nWarning\t关于消息实体的警告信息\tWarn: 199 Miscellaneous warning")]),t._v(" "),n("p",[t._v("HTTP 扩展头部：\nX-Forwarded-For\t后端用来获取用户真实IP的header，即使用户用了代理服务器也可以将代理服务器的IP和请求代理的IP都获取并打印，因此可以用于获得真实IP，当然这个伪造的话就是用来伪造来源（一般可以通过Remote Address获得用户地址，但是这个不在headers中，无法伪造，但是它没有获取代理前面的ip的功能，如果有代理的话就显示代理ip，不会是真实ip）\tX-Forwarded-For: client, proxy1, proxy2\nClient-IP\t\t获取当前请求的客户端IP地址，如果X-Forwarded-For头没用的话就用这个吧")]),t._v(" "),n("p",[t._v("Responses 部分\nHeader\t解释\t示例\nAccept-Ranges\t表明服务器是否支持指定范围请求及哪种类型的分段请求\tAccept-Ranges: bytes\nAge\t从原始服务器到代理缓存形成的估算时间（以秒计，非负）\tAge: 12\nAllow\t对某网络资源的有效的请求行为，不允许则返回405\tAllow: GET, HEAD\nCache-Control\t告诉所有的缓存机制是否可以缓存及哪种类型\tCache-Control: no-cache\nContent-Encoding\tweb服务器支持的返回内容压缩编码类型。\tContent-Encoding: gzip\nContent-Language\t响应体的语言\tContent-Language: en,zh【分别为英语和中文】\nContent-Length\t响应体的长度\tContent-Length: 348\nContent-Location\t请求资源可替代的备用的另一地址\tContent-Location: /index.htm\nContent-MD5\t返回资源的MD5校验值\tContent-MD5: Q2hlY2sgSW50ZWdyaXR5IQ==\nContent-Range\t在整个返回体中本部分的字节位置\tContent-Range: bytes 21010-47021/47022\nContent-Type\t返回内容的MIME类型\tContent-Type: text/html; charset=utf-8\nDate\t原始服务器消息发出的时间\tDate: Tue, 15 Nov 2010 08:12:31 GMT\nETag\t请求变量的实体标签的当前值\tETag: “737060cd8c284d8af7ad3082f209582d”\nExpires\t响应过期的日期和时间\tExpires: Thu, 01 Dec 2010 16:00:00 GMT\nLast-Modified\t请求资源的最后修改时间\tLast-Modified: Tue, 15 Nov 2010 12:45:26 GMT\nLocation\t用来重定向接收方到非请求URL的位置来完成请求或标识新的资源\tLocation: http://www.zcmhi.com/archives/94.html\nPragma\t包括实现特定的指令，它可应用到响应链上的任何接收方\tPragma: no-cache\nProxy-Authenticate\t它指出认证方案和可应用到代理的该URL上的参数\tProxy-Authenticate: Basic\nrefresh\t应用于重定向或一个新的资源被创造，在5秒之后重定向（由网景提出，被大部分浏览器支持）\tRefresh: 5; url=http://www.zcmhi.com/archives/94.html\nRetry-After\t如果实体暂时不可取，通知客户端在指定时间之后再次尝试\tRetry-After: 120\nServer\tweb服务器软件名称\tServer: Apache/1.3.27 (Unix) (Red-Hat/Linux)\nSet-Cookie\t设置Http Cookie\tSet-Cookie: UserID=JohnDoe; Max-Age=3600; Version=1\nTrailer\t指出头域在分块传输编码的尾部存在\tTrailer: Max-Forwards\nTransfer-Encoding\t文件传输编码\tTransfer-Encoding:chunked\nVary\t告诉下游代理是使用缓存响应还是从原始服务器请求\tVary: *\nVia\t告知代理客户端响应是通过哪里发送的\tVia: 1.0 fred, 1.1 nowhere.com (Apache/1.1)\nWarning\t警告实体可能存在的问题\tWarning: 199 Miscellaneous warning\nWWW-Authenticate\t表明客户端请求实体应该使用的授权方案\tWWW-Authenticate: Basic")])])}),[],!1,null,null,null);e.default=o.exports}}]);